import React, { useState, useMemo, useRef, useEffect } from 'react';

// ============================================
// Design Tokens
// ============================================
const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

// ============================================
// SVD Computation
// ============================================
function computeSVD(A) {
  const AtA = [
    [A[0][0]*A[0][0] + A[1][0]*A[1][0], A[0][0]*A[0][1] + A[1][0]*A[1][1]],
    [A[0][0]*A[0][1] + A[1][0]*A[1][1], A[0][1]*A[0][1] + A[1][1]*A[1][1]]
  ];

  let theta;
  if (Math.abs(AtA[0][0] - AtA[1][1]) < 1e-10) {
    theta = Math.PI / 4;
  } else {
    theta = 0.5 * Math.atan2(2 * AtA[0][1], AtA[0][0] - AtA[1][1]);
  }

  const c = Math.cos(theta);
  const s = Math.sin(theta);

  const V = [[c, -s], [s, c]];
  const Vt = [[c, s], [-s, c]];

  const D00 = c*c*AtA[0][0] + 2*c*s*AtA[0][1] + s*s*AtA[1][1];
  const D11 = s*s*AtA[0][0] - 2*c*s*AtA[0][1] + c*c*AtA[1][1];

  const s1 = Math.sqrt(Math.max(0, D00));
  const s2 = Math.sqrt(Math.max(0, D11));
  const S = [s1, s2];

  const AV = [
    [A[0][0]*V[0][0] + A[0][1]*V[1][0], A[0][0]*V[0][1] + A[0][1]*V[1][1]],
    [A[1][0]*V[0][0] + A[1][1]*V[1][0], A[1][0]*V[0][1] + A[1][1]*V[1][1]]
  ];

  const U = [
    [s1 > 1e-10 ? AV[0][0]/s1 : 0, s2 > 1e-10 ? AV[0][1]/s2 : 0],
    [s1 > 1e-10 ? AV[1][0]/s1 : 0, s2 > 1e-10 ? AV[1][1]/s2 : 0]
  ];

  return { U, S, V, Vt, theta };
}

// ============================================
// Transform Visualization
// ============================================
function TransformViz({ A, step }) {
  const canvasRef = useRef(null);
  const size = 260;
  const center = size / 2;
  const scale = 32;

  const { U, S, V, Vt } = useMemo(() => computeSVD(A), [A]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    // Draw grid
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 1;
    for (let i = -4; i <= 4; i++) {
      ctx.beginPath();
      ctx.moveTo(center + i * scale, 0);
      ctx.lineTo(center + i * scale, size);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(0, center + i * scale);
      ctx.lineTo(size, center + i * scale);
      ctx.stroke();
    }

    // Draw axes
    ctx.strokeStyle = theme.colors.textMuted;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(0, center);
    ctx.lineTo(size, center);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(center, 0);
    ctx.lineTo(center, size);
    ctx.stroke();

    // Helper: transform point based on step
    const transformPoint = (x, y) => {
      let px = x, py = y;

      if (step >= 1) {
        const nx = Vt[0][0] * px + Vt[0][1] * py;
        const ny = Vt[1][0] * px + Vt[1][1] * py;
        px = nx; py = ny;
      }
      if (step >= 2) {
        px = S[0] * px;
        py = S[1] * py;
      }
      if (step >= 3) {
        const nx = U[0][0] * px + U[0][1] * py;
        const ny = U[1][0] * px + U[1][1] * py;
        px = nx; py = ny;
      }

      return [center + px * scale, center - py * scale];
    };

    // Draw unit circle / transformed shape
    ctx.beginPath();
    for (let t = 0; t <= 2 * Math.PI; t += 0.05) {
      const x = Math.cos(t);
      const y = Math.sin(t);
      const [px, py] = transformPoint(x, y);
      if (t === 0) ctx.moveTo(px, py);
      else ctx.lineTo(px, py);
    }
    ctx.closePath();

    const colors = [theme.colors.textMuted, theme.colors.pink, theme.colors.yellow, theme.colors.green];
    ctx.strokeStyle = colors[step];
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.fillStyle = `${colors[step]}20`;
    ctx.fill();

    // Draw basis vectors
    const drawVector = (x, y, color) => {
      const [ex, ey] = transformPoint(x, y);
      ctx.strokeStyle = color;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(center, center);
      ctx.lineTo(ex, ey);
      ctx.stroke();

      const angle = Math.atan2(center - ey, ex - center);
      ctx.beginPath();
      ctx.moveTo(ex, ey);
      ctx.lineTo(ex - 10 * Math.cos(angle - 0.4), ey + 10 * Math.sin(angle - 0.4));
      ctx.lineTo(ex - 10 * Math.cos(angle + 0.4), ey + 10 * Math.sin(angle + 0.4));
      ctx.closePath();
      ctx.fillStyle = color;
      ctx.fill();
    };

    drawVector(1, 0, theme.colors.pink);
    drawVector(0, 1, theme.colors.blue);

    // Step label
    const labels = ['Unit Circle', 'After V^T', 'After Sigma', 'After U = A'];
    ctx.fillStyle = theme.colors.text;
    ctx.font = '11px JetBrains Mono';
    ctx.textAlign = 'center';
    ctx.fillText(labels[step], center, size - 8);

  }, [A, step, U, S, Vt]);

  return (
    <canvas
      ref={canvasRef}
      width={size}
      height={size}
      style={{ borderRadius: '10px', display: 'block' }}
    />
  );
}

// ============================================
// Matrix Display
// ============================================
function MatrixDisplay({ matrix, label, color, highlight }) {
  return (
    <div style={{ textAlign: 'center' }}>
      {label && (
        <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '2px' }}>
          {label}
        </div>
      )}
      <div style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: '2px',
        padding: '4px 6px',
        background: highlight ? `${color}15` : 'transparent',
        borderRadius: '6px',
        border: `1px solid ${highlight ? color : theme.colors.border}40`,
      }}>
        <span style={{ color: highlight ? color : theme.colors.textMuted, fontSize: '16px', fontWeight: '200' }}>[</span>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1px' }}>
          {matrix.map((row, i) => (
            <div key={i} style={{ display: 'flex', gap: '4px' }}>
              {row.map((val, j) => (
                <div key={j} style={{
                  width: '32px',
                  height: '20px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '10px',
                  fontWeight: '600',
                  color: theme.colors.text,
                }}>
                  {typeof val === 'number' ? val.toFixed(2) : val}
                </div>
              ))}
            </div>
          ))}
        </div>
        <span style={{ color: highlight ? color : theme.colors.textMuted, fontSize: '16px', fontWeight: '200' }}>]</span>
      </div>
    </div>
  );
}

