export default function SVDPlayground() {
  const [exampleIdx, setExampleIdx] = useState(0);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);

  const examples = [
    { name: 'Symmetric', A: [[2, 1], [1, 2]] },
    { name: 'Shear', A: [[1, 1], [0, 1]] },
    { name: 'Scale', A: [[3, 0], [0, 1]] },
    { name: 'General', A: [[1, 2], [3, 4]] },
  ];

  const A = examples[exampleIdx].A;
  const { U, S, V, Vt } = useMemo(() => computeSVD(A), [A]);

  const reset = () => { setStep(0); setPlaying(false); };
  const next = () => step < 3 && setStep(step + 1);
  const prev = () => step > 0 && setStep(step - 1);

  const auto = async () => {
    setPlaying(true);
    for (let s = 0; s <= 3; s++) {
      setStep(s);
      await new Promise(r => setTimeout(r, 1200));
    }
    setPlaying(false);
  };

  const stepInfo = [
    { title: "Start: Unit Circle", desc: "We begin with a circle of radius 1. Every point is distance 1 from the origin.", color: theme.colors.textMuted },
    { title: "Step 1: First Rotation (V^T)", desc: "Rotate to align with the natural directions of the transformation. Think of finding the best angle to view the stretch.", color: theme.colors.pink },
    { title: "Step 2: Stretch (Sigma)", desc: `Stretch horizontally by ${S[0].toFixed(2)}x, vertically by ${S[1].toFixed(2)}x. The circle becomes an ellipse. These are the singular values.`, color: theme.colors.yellow },
    { title: "Step 3: Second Rotation (U)", desc: "Final rotation to match the output orientation. Now we have reconstructed exactly what matrix A does.", color: theme.colors.green },
  ];

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.colors.background,
      color: theme.colors.text,
      fontFamily: theme.font,
      padding: '16px',
    }}>
      <div style={{ maxWidth: '480px', margin: '0 auto' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '16px' }}>
          <h1 style={{ fontSize: '18px', fontWeight: '700', margin: 0 }}>SVD Decomposition</h1>
          <p style={{ color: theme.colors.textSecondary, fontSize: '11px', marginTop: '4px' }}>
            Any matrix = Rotate, Stretch, Rotate
          </p>
        </div>

        {/* Example Tabs */}
        <div style={{ display: 'flex', gap: '6px', justifyContent: 'center', marginBottom: '16px' }}>
          {examples.map((e, idx) => (
            <button
              key={idx}
              onClick={() => { setExampleIdx(idx); reset(); }}
              style={{
                padding: '6px 12px',
                background: exampleIdx === idx ? theme.colors.primary : theme.colors.surface,
                border: 'none',
                borderRadius: '6px',
                color: exampleIdx === idx ? '#fff' : theme.colors.textSecondary,
                fontFamily: theme.font,
                fontSize: '11px',
                cursor: 'pointer',
              }}
            >
              {e.name}
            </button>
          ))}
        </div>

        {/* Main Card */}
        <div style={{ background: theme.colors.surfaceAlt, borderRadius: '12px', padding: '16px' }}>

          {/* Visualization */}
          <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '12px' }}>
            <TransformViz A={A} step={step} />
          </div>

          {/* Step Explanation - ALWAYS RIGHT AFTER GRAPH */}
          <div style={{
            padding: '12px',
            background: theme.colors.surface,
            borderRadius: '8px',
            borderLeft: `3px solid ${stepInfo[step].color}`,
            marginBottom: '12px',
          }}>
            <div style={{ fontSize: '12px', fontWeight: '600', color: theme.colors.text, marginBottom: '4px' }}>
              {stepInfo[step].title}
            </div>
            <div style={{ fontSize: '11px', color: theme.colors.textSecondary, lineHeight: 1.5 }}>
              {stepInfo[step].desc}
            </div>
          </div>

          {/* SVD Decomposition - Always visible */}
          <div style={{ marginBottom: '12px' }}>
            <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '6px', textAlign: 'center' }}>
              A = U x Sigma x V^T
            </div>
            <div style={{ display: 'flex', gap: '4px', justifyContent: 'center', alignItems: 'center', flexWrap: 'wrap' }}>
              <MatrixDisplay matrix={A} label="A" color={theme.colors.text} highlight={false} />
              <span style={{ color: theme.colors.textMuted, fontSize: '12px' }}>=</span>
              <MatrixDisplay matrix={U} label="U" color={theme.colors.green} highlight={step >= 3} />
              <span style={{ color: theme.colors.textMuted, fontSize: '10px' }}>x</span>
              <MatrixDisplay 
                matrix={[[S[0].toFixed(1), '0'], ['0', S[1].toFixed(1)]]} 
                label="Sigma" 
                color={theme.colors.yellow} 
                highlight={step >= 2} 
              />
              <span style={{ color: theme.colors.textMuted, fontSize: '10px' }}>x</span>
              <MatrixDisplay matrix={Vt} label="V^T" color={theme.colors.pink} highlight={step >= 1} />
            </div>
          </div>

          {/* Singular Values */}
          <div style={{
            padding: '10px',
            background: theme.colors.surface,
            borderRadius: '8px',
            marginBottom: '12px',
          }}>
            <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '6px', textAlign: 'center' }}>
              SINGULAR VALUES (stretch factors)
            </div>
            <div style={{ display: 'flex', gap: '24px', justifyContent: 'center' }}>
              <div style={{ textAlign: 'center' }}>
                <span style={{ fontSize: '18px', fontWeight: '700', color: step >= 2 ? theme.colors.yellow : theme.colors.textMuted }}>
                  {S[0].toFixed(2)}
                </span>
                <div style={{ fontSize: '9px', color: theme.colors.textMuted }}>sigma 1</div>
              </div>
              <div style={{ textAlign: 'center' }}>
                <span style={{ fontSize: '18px', fontWeight: '700', color: step >= 2 ? theme.colors.yellow : theme.colors.textMuted }}>
                  {S[1].toFixed(2)}
                </span>
                <div style={{ fontSize: '9px', color: theme.colors.textMuted }}>sigma 2</div>
              </div>
            </div>
          </div>

          {/* Step Indicator */}
          <div style={{ display: 'flex', gap: '4px', justifyContent: 'center', marginBottom: '12px' }}>
            {[0, 1, 2, 3].map(i => (
              <div
                key={i}
                onClick={() => setStep(i)}
                style={{
                  width: i === step ? '20px' : '8px',
                  height: '8px',
                  borderRadius: '4px',
                  background: i <= step ? theme.colors.primary : theme.colors.border,
                  cursor: 'pointer',
                  transition: 'all 0.3s',
                }}
              />
            ))}
          </div>

          {/* Controls */}
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
            <button onClick={prev} disabled={step <= 0} style={{
              padding: '10px 14px',
              background: theme.colors.surface,
              border: 'none',
              borderRadius: '8px',
              color: step <= 0 ? theme.colors.textMuted : theme.colors.text,
              cursor: step <= 0 ? 'not-allowed' : 'pointer',
              fontSize: '14px',
            }}>
              ←
            </button>

            <button onClick={next} disabled={step >= 3} style={{
              flex: 1,
              padding: '12px',
              background: step < 3 ? theme.colors.primary : theme.colors.positive,
              border: 'none',
              borderRadius: '8px',
              color: '#fff',
              fontFamily: theme.font,
              fontSize: '12px',
              fontWeight: '600',
              cursor: step < 3 ? 'pointer' : 'default',
            }}>
              {step === 0 ? 'Start' : step < 3 ? 'Next Step' : 'Complete'}
            </button>

            <button onClick={auto} disabled={playing || step >= 3} style={{
              padding: '10px 14px',
              background: theme.colors.surface,
              border: 'none',
              borderRadius: '8px',
              color: playing || step >= 3 ? theme.colors.textMuted : theme.colors.text,
              cursor: playing || step >= 3 ? 'not-allowed' : 'pointer',
              fontSize: '12px',
            }}>
              ▶▶
            </button>

            <button onClick={reset} style={{
              padding: '10px 14px',
              background: theme.colors.surface,
              border: 'none',
              borderRadius: '8px',
              color: theme.colors.text,
              cursor: 'pointer',
              fontSize: '14px',
            }}>
              ↺
            </button>
          </div>
        </div>

        {/* Key Insight */}
        <div style={{
          marginTop: '12px',
          padding: '10px 14px',
          background: theme.colors.surface,
          borderRadius: '8px',
          fontSize: '10px',
          color: theme.colors.textSecondary,
          textAlign: 'center',
        }}>
          <strong style={{ color: theme.colors.text }}>Why it matters:</strong> SVD reveals how much a transformation stretches in each direction. Used in image compression, recommendations, and data analysis.
        </div>
      </div>
    </div>
  );
}
